diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..94c3e7fe17e6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,138 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp pred (select (fcmp ord X, 0), X, 0), C --> fcmp pred X, C
+      // when the predicate and constant satisfy safety condition.
+      {
+        Value *XVal, *ZeroVal;
+        ConstantFP *CFP = dyn_cast<ConstantFP>(RHSC);
+        const APFloat *C = nullptr;
+        if (CFP) {
+          C = &CFP->getValueAPF();
+          // For vector constants, only handle splat.
+          if (CFP->getType()->isVectorTy()) {
+            if (auto *Splat = CFP->getSplatValue())
+              C = &cast<ConstantFP>(Splat)->getValueAPF();
+            else
+              CFP = nullptr;
+          }
+        }
+        if (CFP) {
+          CmpPredicate Pred2;
+          // Match ord pattern: select (fcmp ord X, 0), X, 0
+          if (match(LHSI, m_Select(m_FCmp(Pred2, m_Value(XVal), m_AnyZeroFP()),
+                                   m_Deferred(XVal), m_Value(ZeroVal))) &&
+              Pred2 == FCmpInst::FCMP_ORD && match(ZeroVal, m_AnyZeroFP())) {
+            // Determine if transformation is safe.
+            bool Safe = false;
+            // For ordered predicates, need fcmp Pred 0, C == false.
+            // For unordered predicates, need fcmp Pred 0, C == true.
+            switch (Pred) {
+            default:
+              break;
+            case FCmpInst::FCMP_OEQ:
+              Safe = !C->isZero();
+              break;
+            case FCmpInst::FCMP_ONE:
+              Safe = C->isZero();
+              break;
+            case FCmpInst::FCMP_OGT:
+              // 0 > C ? false when C >= 0
+              Safe = C->isZero() || !C->isNegative();
+              break;
+            case FCmpInst::FCMP_OGE:
+              // 0 >= C ? false when C > 0
+              Safe = !C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_OLT:
+              // 0 < C ? false when C <= 0
+              Safe = C->isZero() || C->isNegative();
+              break;
+            case FCmpInst::FCMP_OLE:
+              // 0 <= C ? false when C < 0
+              Safe = C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_UEQ:
+              Safe = C->isZero();
+              break;
+            case FCmpInst::FCMP_UNE:
+              Safe = !C->isZero();
+              break;
+            case FCmpInst::FCMP_UGT:
+              // 0 > C ? true when C < 0
+              Safe = C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_UGE:
+              // 0 >= C ? true when C <= 0
+              Safe = C->isZero() || C->isNegative();
+              break;
+            case FCmpInst::FCMP_ULT:
+              // 0 < C ? true when C > 0
+              Safe = !C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_ULE:
+              // 0 <= C ? true when C >= 0
+              Safe = C->isZero() || !C->isNegative();
+              break;
+            }
+            if (Safe) {
+              return new FCmpInst(Pred, XVal, RHSC, "", &I);
+            }
+          }
+          // Match uno pattern: select (fcmp uno X, 0), 0, X
+          if (match(LHSI, m_Select(m_FCmp(Pred2, m_Value(XVal), m_AnyZeroFP()),
+                                   m_Value(ZeroVal), m_Deferred(XVal))) &&
+              Pred2 == FCmpInst::FCMP_UNO && match(ZeroVal, m_AnyZeroFP())) {
+            bool Safe = false;
+            switch (Pred) {
+            default:
+              break;
+            case FCmpInst::FCMP_OEQ:
+              Safe = !C->isZero();
+              break;
+            case FCmpInst::FCMP_ONE:
+              Safe = C->isZero();
+              break;
+            case FCmpInst::FCMP_OGT:
+              Safe = C->isZero() || !C->isNegative();
+              break;
+            case FCmpInst::FCMP_OGE:
+              Safe = !C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_OLT:
+              Safe = C->isZero() || C->isNegative();
+              break;
+            case FCmpInst::FCMP_OLE:
+              Safe = C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_UEQ:
+              Safe = C->isZero();
+              break;
+            case FCmpInst::FCMP_UNE:
+              Safe = !C->isZero();
+              break;
+            case FCmpInst::FCMP_UGT:
+              Safe = C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_UGE:
+              Safe = C->isZero() || C->isNegative();
+              break;
+            case FCmpInst::FCMP_ULT:
+              Safe = !C->isNegative() && !C->isZero();
+              break;
+            case FCmpInst::FCMP_ULE:
+              Safe = C->isZero() || !C->isNegative();
+              break;
+            }
+            if (Safe) {
+              return new FCmpInst(Pred, XVal, RHSC, "", &I);
+            }
+          }
+        }
+      }
+
+      if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
+        return NV;
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

